import{_ as a,o as t,c as b,j as r,a as p,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const h=JSON.parse('{"title":"攻城坦克","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/7.载具及随从/载具/2.C级/攻城坦克.md","filePath":"4.资源分区/7.物品与装备/7.载具及随从/载具/2.C级/攻城坦克.md"}'),s={name:"4.资源分区/7.物品与装备/7.载具及随从/载具/2.C级/攻城坦克.md"};function o(d,e,i,l,m,_){return t(),b("div",null,[...e[0]||(e[0]=[r("h1",{id:"攻城坦克",tabindex:"-1"},[p("攻城坦克 "),r("a",{class:"header-anchor",href:"#攻城坦克","aria-label":'Permalink to "攻城坦克"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风028")])])],-1),n('<h1 id="攻城坦克-1" tabindex="-1">攻城坦克 <a class="header-anchor" href="#攻城坦克-1" aria-label="Permalink to &quot;攻城坦克&quot;">​</a></h1><p>（出自星际争霸）<br> 攻城坦克<br> 价格：C+2000<br> “源自2491年旧联邦时期就制造并生成的光弧系列攻城坦克，其最初是作为固定炮台的定位来设计，后为了灵活适应多变的战场形势，逐渐演变为兼具机动性与重火力，且具有双部署模式的革命性远程支援载具。之后在蒙斯克的大力推动下，帝国生产出了新型的穿冲攻城坦克，虽然问题依旧，但这次的售后服务明显好上了许多”<br> 不过在战场上，攻城坦克往往是比敌军更为危险的存在——前线的陆战队员们总是如此抱怨道。</p><p>类别：重型载具<br> 体积：14<br> 结构值：36<br> 装甲：20<br> 速度：60/轮<br> 载员：驾驶员1</p><p>【炮平四海】：以一个自由动作宣言，进入或退出【攻城模式】。攻城坦克展开两侧的液压腿，主履带向外定向展开稳固车体，此状态下你无法移动（同样无法进行紧急规避），该状态下装甲数值增加3点处理。<br> 在【攻城模式下】，你使用载具武器攻击时变为不分敌我，目标落点半径30m圆形的范围伤害。</p><p>【重型载具】：攻城坦克驾驶员与乘客提供全遮蔽效果，与额外的遮蔽防御，其数值为载具体积/被遮蔽者体积取低，同时具有基于护甲防御的【防弹】。</p><p>【载具升级】<br> 悬浮攻城模式<br> 价格：250<br> 来自重锤要塞军士“巴玛·科瓦尔斯基”她所驾驶攻城坦克的改造——通过大力出奇迹的方式，在攻城坦克底盘装上更劲的推进器，让攻城坦克不必解除【攻城模式】来移动。以履带不沾地，通过推进器推动的方式进行移动。虽然整出的动静一点都不小，但和开炮声一比还是很好接受的。</p><p>购买本升级后，攻城坦克获得免疫D级困难地形的能力，并且【攻城模式】可以不再令攻城坦克无法移动，但获得的护甲值增加也降低至1点。</p><p>喷气火箭挂载<br> 价格：D+1000<br> 帝国内部没有广泛装备的辅助科技，一般只在执行秘密任务的精英单位中装备——例如诺娃的隐蔽部队，装备喷气火箭挂载后，攻城坦克得以跨越不少困难地形直接占领高点，为其他队友提供火力支援。<br> 但话又说回来，其实派一艘运输机也有差不多的效果，不派一般是敌方掌握了制空权，那飞到高点的攻城坦克就很容易成为活靶子。</p><p>购买本升级后，攻城坦克获得起飞跨越障碍的能力，可以在驾驶移动期间进行跳跃行为，能准确的控制跳跃的落点和距离而无需检定，但跳跃的高度不能超过此次移动距离的1/2。<br> 喷气火箭挂载在降落时也能提供反推力，这视为一个免疫坠落伤害的效果。而为了保护这些额外的挂载，攻城坦克的护甲得到了进一步强化，获得2点穿刺物理伤害吸收。</p><p>【下属武器/武器附件】<br> 双发90mm等离子火炮/180mm冲击炮<br> 价格：C+1000<br> 全地形无阻使用，以火力覆盖碾碎帝国一切来敌的强力火炮，当它的炮声响起，足够吓退除虫族以外的敌人。在寻常状态为90mm火炮，当进入【攻城模式】后，90mm火炮将横向展开炮管，转变为威力惊人的180mm冲击炮。</p><p>武器伤害：13L<br> 武器特性：【高速10】【破甲5】【贯穿】<br> 伤害类型：物理-穿刺<br> 射程：200m<br> 装弹量：1<br> 【备弹充足】：考虑到攻城坦克每次出战都要倾泻相当数量的弹药，而且轮回者没有战地补给的机会，主神因此在车体内准备了充足的弹药，视为其拥有【无限子弹】特性。</p><p>升级-定向冲击<br> 价格：250<br> 面对攻城坦克居高不下的友军误伤率，拉尔斯科技研发了这款智能弹药，通过识别友军的频率减少对应方向的爆炸威力从而减轻对友军的杀伤，实验室效果最高可达75%！但我们的主神看不得这点瑕疵，将这个数值提高到了100%！实现了真正的零误伤率。<br> 购买本升级后，【攻城模式】下的攻击可以不再痛击友军，但杀伤范围减半<br> 选开：若其他pl与主持人一致同意，则可令效果变为【攻城模式】下对友方单位的伤害减少75%，持续到本场影片结束为止。</p><p>升级-漩流弹mini<br> 价格：D+500<br> 这一新型的弹头在保证攻城坦克原有范围杀伤的前提下，额外提高了对主目标的杀伤力。两炮一个追猎，一炮干碎同行，不可称不厉害。<br> 虽然在主神空间其的威力被大大削弱，但仍旧拥有不错的威力。<br> 购买本升级后，【攻城模式】下的攻击获得3L武器伤害提升与5点破甲。</p><p>升级-漩流弹<br> 前置：升级-漩流弹mini<br> 价格：C+2000（差价）<br> 这一新型的弹头在保证攻城坦克原有范围杀伤的前提下，额外提高了对主目标的杀伤力。一炮让不朽汗颜，两炮令雷神跑路，实乃重甲克星。<br> 虽然在主神空间其的威力被削弱不少，但仍旧拥有可观的威力。<br> 如果你拥有“漩流弹mini”则可以差价升级为“漩流弹”<br> 购买本升级后，【攻城模式】下的攻击获得6L武器伤害提升与5点破甲、5点威猛。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',16)])])}const f=a(s,[["render",o]]);export{h as __pageData,f as default};
